You can use a custom field that accepts empty strings as input. From https://github.com/marshmallow-code/marshmallow/issues/583#issuecomment-285249535 : 

```python
from marshmallow import Schema, fields

class StrInt(fields.Int):

    def _deserialize(self, value, attr, data):
        if value == '':
            if not self.allow_none:
                self.fail('null')
            return None
        return super()._deserialize(value, attr, data)

class MySchema(Schema):
    id = StrInt(allow_none=True)


schema = MySchema(strict=True)

print(schema.load({'id': ''}).data)  # {'id': None}
```

I using custom fields for arrow type in marshmallow serialize/deserialize
``` python
class Arrow(Field):
    default_timezone = 'UTC'
    default_format = 'YYYY-MM-DD HH:mm:ss'
    default_error_messages = {
        'invalid': 'Invalid datetime value {value}'
    }

    def __init__(self, format_=None, timezone=None, to_timezone=None, **kwargs):
        super(Arrow, self).__init__(**kwargs)
        self.format = format_ or self.default_format
        self.timezone = timezone or self.default_timezone
        self.to_timezone = to_timezone

    def _serialize(self, value, attr, obj):
        if not value:
            return value
        return value.to(self.default_timezone).format(self.format)

    def _deserialize(self, value, attr, data):
        if value is None:
            return None
        try:
            v = arrow.get(value, self.format).replace(tzinfo=self.timezone)
            if self.to_timezone:
                return v.to(self.to_timezone)
            return v
        except (TypeError, ValueError, ParserError):
            return self.fail('invalid', value=value)
```
``` python
created_at = fields.Arrow(to_timezone='UTC', format_='hh:mm', required=False)
```
